const item = $input.first();
const body = item.json.body || item.json;

const bank_account_id = parseInt(body.bank_account_id, 10);
if (!Number.isFinite(bank_account_id) || bank_account_id <= 0) {
  throw new Error('bank_account_id form field must be a positive integer');
}

// Confirm a CSV binary attachment is present.
const binary = item.binary || {};
const csvKey = binary.csv ? 'csv' : Object.keys(binary)[0];
if (!csvKey || !binary[csvKey]) {
  throw new Error('multipart upload missing the csv file (expected form field name: csv)');
}
const f = binary[csvKey];
if ((f.fileSize || (f.data ? f.data.length : 0)) > 5 * 1024 * 1024) {
  throw new Error('csv file exceeds 5MB safety cap');
}

return [{
  json: { bank_account_id, csv_filename: f.fileName || 'upload.csv' },
  binary: { csv: f }
}];

// Maps pdfplumber's parsed rows (column names from CSV header) to the
// {transaction_date, amount, description, reference, balance} schema that
// import_bank_transactions() expects. Tries common UK-bank column variants.
//
// Returns the mapped rows + a hash of the input for event idempotency.

const pdfp = $input.first().json;
const rows = pdfp.data;
if (!Array.isArray(rows) || rows.length === 0) {
  throw new Error('pdfplumber returned no rows — empty CSV?');
}
if (rows.length > 10000) {
  throw new Error(`pdfplumber returned ${rows.length} rows — exceeds 10000-row safety cap`);
}

const lc = s => String(s).toLowerCase().trim();
const sample = rows[0];
const cols = Object.fromEntries(Object.keys(sample).map(k => [lc(k), k]));

const pickCol = (...candidates) => {
  for (const c of candidates) {
    if (cols[lc(c)] !== undefined) return cols[lc(c)];
  }
  return null;
};

const dateCol  = pickCol('transaction_date', 'date', 'transaction date', 'posted date', 'value date');
const amtCol   = pickCol('amount', 'value');
const inCol    = pickCol('money in', 'credit', 'paid in');
const outCol   = pickCol('money out', 'debit', 'paid out');
const descCol  = pickCol('description', 'narrative', 'details', 'transaction description');
const refCol   = pickCol('reference', 'reference_id', 'ref');
const balCol   = pickCol('balance', 'running balance');

if (!dateCol) throw new Error(`CSV missing date column (looked for: transaction_date/date/transaction date/posted date)`);
if (!amtCol && !(inCol || outCol)) {
  throw new Error('CSV missing amount column (need either "amount" OR "money in"+"money out")');
}

const toIsoDate = v => {
  if (!v) return null;
  const s = String(v).trim();
  if (/^\d{4}-\d{2}-\d{2}$/.test(s)) return s;
  const m = s.match(/^(\d{2})[/-](\d{2})[/-](\d{4})$/);
  if (m) return `${m[3]}-${m[2]}-${m[1]}`; // assume DD/MM/YYYY (UK)
  const m2 = s.match(/^(\d{4})[/-](\d{2})[/-](\d{2})$/);
  if (m2) return `${m2[1]}-${m2[2]}-${m2[3]}`;
  return null;
};

const toNumber = v => {
  if (v === null || v === undefined || v === '') return null;
  const n = Number(String(v).replace(/[£$,\s]/g, ''));
  return Number.isFinite(n) ? n : null;
};

const mapped = [];
for (const [i, r] of rows.entries()) {
  const td = toIsoDate(r[dateCol]);
  if (!td) throw new Error(`row ${i}: cannot parse date '${r[dateCol]}'`);

  let amount;
  if (amtCol) {
    amount = toNumber(r[amtCol]);
  } else {
    const moneyIn  = toNumber(r[inCol]) || 0;
    const moneyOut = toNumber(r[outCol]) || 0;
    amount = moneyIn - moneyOut;
  }
  if (amount === null || !Number.isFinite(amount)) {
    throw new Error(`row ${i}: cannot parse amount`);
  }

  mapped.push({
    transaction_date: td,
    amount,
    description: descCol ? String(r[descCol] || '') : '',
    reference:   refCol  ? String(r[refCol]  || '') : null,
    balance:     balCol  ? toNumber(r[balCol])      : null
  });
}

const crypto = require('crypto');
const input_hash = crypto.createHash('sha256')
  .update(JSON.stringify({ bank_account_id: $('Validate Form Input').first().json.bank_account_id, rows: mapped }))
  .digest('hex')
  .slice(0, 16);

return [{
  json: {
    bank_account_id: $('Validate Form Input').first().json.bank_account_id,
    rows_json:       JSON.stringify(mapped),
    input_hash,
    row_count:       mapped.length
  }
}];

