// One bank.imported summary event per upload. Per-row bank.transaction
// events are deferred until bank_pipeline (Xero matching) is built —
// emitting them now would just queue events the router has nowhere to send.

const crypto = require('crypto');

const vaultData = $('Vault: Signing Key').first().json;
const signing_key = vaultData?.data?.data?.payload_hmac_key;
if (!signing_key) {
  throw new Error('signing key not returned by vault — check vault-token-header credential scope');
}

const summary = $input.first().json;
const inputData = $('Map CSV Columns').first().json;

const payload = {
  bank_account_id: summary.bank_account_id,
  entity_id:       summary.entity_id,
  rows_received:   summary.rows_received,
  rows_inserted:   summary.rows_inserted,
  date_min:        summary.date_min,
  date_max:        summary.date_max,
  source:          'csv_upload'
};

const canonical = JSON.stringify(payload, Object.keys(payload).sort());
const signature = crypto.createHmac('sha256', signing_key)
                        .update(canonical)
                        .digest('hex');

return [{
  json: {
    event_type:        'bank.imported',
    source:            'bank_csv_import',
    entity_id:         summary.entity_id,
    payload_json:      JSON.stringify(payload),
    payload_signature: signature,
    idempotency_key:   'bank_imported_' + inputData.input_hash,
    pipeline_version:  '1.0',
    bank_account_id:   summary.bank_account_id,
    rows_received:     summary.rows_received,
    rows_inserted:     summary.rows_inserted,
    date_min:          summary.date_min,
    date_max:          summary.date_max
  }
}];
